const raw = $input.first().json || {};
const body = raw.body || raw;
const workflowRun = body.workflow_run || body;
const conclusion = String(workflowRun.conclusion || body.conclusion || 'unknown').toLowerCase();
if (['success', 'skipped', 'cancelled'].includes(conclusion)) {
  return [];
}

const runId = String(workflowRun.id || body.run_id || '').trim();
const workflowName = String(workflowRun.name || body.workflow_name || 'GitHub Actions').trim();
const branch = String(workflowRun.head_branch || body.branch || '').trim();
const commitSHA = String(workflowRun.head_sha || body.commit_sha || '').trim();
const dedupSeed = runId || commitSHA || workflowName.toLowerCase().replace(/\s+/g, '-');

return [{ json: {
  router_mode: 'intake',
  schema_version: 1,
  source: 'n8n',
  type: 'ci_failure',
  project_key: 'pbs',
  title: 'Investigate PBS CI failure: ' + workflowName,
  action_key: '',
  dedup_key: 'ci_failure:pbs:' + dedupSeed,
  requested_by: 'github-actions',
  payload: {
    run_id: runId,
    workflow_name: workflowName,
    conclusion,
    branch,
    commit_sha: commitSHA,
    html_url: String(workflowRun.html_url || body.html_url || ''),
    raw_event: body
  }
} }];
